import json, os

base = os.path.join(os.path.dirname(__file__), "data", "calculators", "unit")

def write_json(subcat, slug, data):
    path = os.path.join(base, subcat, f"{slug}.json")
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, 'w', encoding='utf-8') as f:
        json.dump(data, f, ensure_ascii=False, indent=2)
    print(f"  {subcat}/{slug}.json")

def make_calc(slug, subcat, title, desc, metaTitle, metaDesc, funcName, inputs, outputs, explanation, faq, related=[], popular=False):
    return {
        "slug": slug,
        "category": "unit",
        "subcategory": subcat,
        "title": title,
        "description": desc,
        "metaTitle": metaTitle,
        "metaDescription": metaDesc,
        "calculatorFunction": funcName,
        "inputs": inputs,
        "outputs": outputs,
        "explanation": explanation,
        "faq": faq,
        "related": related,
        "popular": popular
    }

def num_input(id, label, default=1, min_v=0, max_v=999999999, step=0.01):
    return {"id": id, "label": label, "type": "number", "unit": "", "default": default, "min": min_v, "max": max_v, "step": step}

def dir_select(a_val, a_label, b_val, b_label):
    return {"id": "direction", "label": "変換方向", "type": "select", "options": [
        {"value": "a_to_b", "label": f"{a_label} \u2192 {b_label}"},
        {"value": "b_to_a", "label": f"{b_label} \u2192 {a_label}"}
    ], "default": "a_to_b"}

def out(id, label, primary=False):
    r = {"id": id, "label": label, "format": "number"}
    if primary:
        r["primary"] = True
    return r

def make_converter(subcat, slug, title, desc, metaTitle, metaDesc, funcName, a_val, a_label, b_val, b_label, default_val, explanation, faq, popular=False, min_v=0, step=0.01):
    calc = make_calc(slug, subcat, title, desc, metaTitle, metaDesc, funcName,
        [num_input("value", "数値", default=default_val, min_v=min_v, step=step), dir_select(a_val, a_label, b_val, b_label)],
        [out("result", "変換結果", True), out("formula", "計算式")],
        explanation, faq, [], popular)
    write_json(subcat, slug, calc)

